// Nächsten 'generated' Pin auswählen (frühestes scheduled_at)
const raw = items[0].binary?.data?.data || items[0].json?.data;
let pinsData;
try {
  const str = Buffer.isBuffer(raw) ? raw.toString('utf8') : JSON.stringify(raw);
  pinsData = JSON.parse(str);
} catch(e) {
  throw new Error('pins.json konnte nicht geparst werden: ' + e.message);
}

const pin = pinsData.pins
  .filter(p => p.status === 'generated')
  .sort((a, b) => new Date(a.scheduled_at) - new Date(b.scheduled_at))[0];

if (!pin) {
  return [{ json: { found: false, message: 'Kein generierter Pin in der Queue.' } }];
}

return [{
  json: {
    found: true,
    id: pin.id,
    template: pin.template,
    lang: pin.lang,
    board_id: pin.board_id,
    link: pin.pinterest.link,
    title: pin.pinterest.title,
    description: pin.pinterest.description + '\n\n' + pin.pinterest.hashtags,
    png_path: $env.PROJECT_PATH + '/pinterest/generated/' + pin.id + '.png',
    pins_json_path: $env.PROJECT_PATH + '/pinterest/pins.json',
    pins_data: JSON.stringify(pinsData)
  }
}];

// PNG binary → base64 string für Pinterest API
const binaryKey = Object.keys(items[0].binary || {})[0];
if (!binaryKey) throw new Error('Keine Binärdaten gefunden');

const buf = Buffer.from(items[0].binary[binaryKey].data, 'base64');
const base64png = buf.toString('base64');

return [{
  json: {
    ...items[0].json,
    image_base64: base64png
  },
  binary: items[0].binary
}];

// pins.json aktualisieren: status → posted
const pinId     = $('Nächsten Pin auswählen').first().json.id;
const pinsRaw   = $('Nächsten Pin auswählen').first().json.pins_data;
const pinsData  = JSON.parse(pinsRaw);
const pinPinId  = items[0].json?.id || null;

const pin = pinsData.pins.find(p => p.id === pinId);
if (pin) {
  pin.status           = 'posted';
  pin.posted_at        = new Date().toISOString();
  pin.pinterest_pin_id = pinPinId;
}

// Prüfen ob Queue niedrig ist (< 2 generierte Pins übrig)
const remaining = pinsData.pins.filter(p => p.status === 'generated').length;

return [{
  json: {
    pins_json_updated: JSON.stringify(pinsData, null, 2),
    pins_json_path: $('Nächsten Pin auswählen').first().json.pins_json_path,
    queue_low: remaining < 2,
    remaining_generated: remaining,
    posted_id: pinId
  }
}];
